import { useEffect, useState} from "react";

import CourseCard from "../Components/CourseCard";

import Courses from "../Files/Tests/UserCoursesTest.json"

function MainPage() {

  const [courses, setCourses] = useState([]);

  useEffect(() => {
    const courses = Courses;

    setCourses(courses);
  }, []);

  return (
    <div className="main-page">
      
      <div className="lesson-filter-container">
        <div className="filter">
          <h4>Сортировать по</h4>
          <select id="group--1" style={{ padding: "0 0 016px" }}>
            <option>Дата создания</option>
            <option>Количество покупок</option>
            <option>Рейтинг</option>
          </select>
        </div>

        <div className="lessons">
          <ul>
            {courses.map((item,index)=>(
              <li>
                <CourseCard key={index} courseInfo={item}/>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
}

export default MainPage;
